static void jayess_libuv_udp_alloc_cb(uv_handle_t *handle, size_t suggested_size, uv_buf_t *buf) {
    (void)handle;
    buf->base = (char *)malloc(suggested_size > 0 ? suggested_size : 1);
    buf->len = (unsigned int)(suggested_size > 0 ? suggested_size : 1);
}

static void jayess_libuv_udp_recv_cb(uv_udp_t *handle, ssize_t nread, const uv_buf_t *buf, const struct sockaddr *addr, unsigned flags) {
    jayess_libuv_udp_socket *socket = NULL;
    jayess_object *result = NULL;
    char ip[64];
    int port = 0;
    (void)flags;
    if (handle == NULL) {
        if (buf != NULL && buf->base != NULL) {
            free(buf->base);
        }
        return;
    }
    socket = (jayess_libuv_udp_socket *)handle->data;
    if (socket == NULL || socket->callback == NULL) {
        if (buf != NULL && buf->base != NULL) {
            free(buf->base);
        }
        return;
    }
    result = jayess_object_new();
    if (nread < 0) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "data", jayess_value_undefined());
        jayess_object_set_value(result, "address", jayess_value_undefined());
        jayess_object_set_value(result, "port", jayess_value_undefined());
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string(uv_strerror((int)nread))));
        jayess_call_function(socket->callback, jayess_value_from_object(result));
        if (buf != NULL && buf->base != NULL) {
            free(buf->base);
        }
        return;
    }
    if (nread == 0 || addr == NULL) {
        if (buf != NULL && buf->base != NULL) {
            free(buf->base);
        }
        return;
    }
    memset(ip, 0, sizeof(ip));
    if (addr->sa_family == AF_INET) {
        const struct sockaddr_in *sa = (const struct sockaddr_in *)addr;
        uv_ip4_name(sa, ip, sizeof(ip));
        port = ntohs(sa->sin_port);
    }
    jayess_object_set_value(result, "ok", jayess_value_from_bool(1));
    {
        char *text = (char *)malloc((size_t)nread + 1);
        if (text == NULL) {
            jayess_object_set_value(result, "data", jayess_value_undefined());
        } else {
            memcpy(text, buf->base, (size_t)nread);
            text[nread] = '\0';
            jayess_object_set_value(result, "data", jayess_value_from_string(text));
            free(text);
        }
    }
    jayess_object_set_value(result, "address", jayess_value_from_string(ip));
    jayess_object_set_value(result, "port", jayess_value_from_number((double)port));
    jayess_object_set_value(result, "error", jayess_value_undefined());
    jayess_call_function(socket->callback, jayess_value_from_object(result));
    if (buf != NULL && buf->base != NULL) {
        free(buf->base);
    }
}

