static void jayess_libuv_tcp_connect_cb(uv_connect_t *req, int status) {
    jayess_libuv_tcp_connect_request *connect_req = (jayess_libuv_tcp_connect_request *)req;
    jayess_object *result = NULL;
    if (connect_req == NULL || connect_req->client == NULL || connect_req->client->connect_callback == NULL) {
        free(connect_req);
        return;
    }
    result = jayess_object_new();
    if (status < 0) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string(uv_strerror(status))));
    } else {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(1));
        jayess_object_set_value(result, "error", jayess_value_undefined());
    }
    jayess_call_function(connect_req->client->connect_callback, jayess_value_from_object(result));
    free(connect_req);
}

static void jayess_libuv_tcp_connection_cb(uv_stream_t *server_stream, int status) {
    jayess_libuv_tcp_server *server = NULL;
    jayess_libuv_tcp_client *client = NULL;
    jayess_object *result = NULL;
    if (server_stream == NULL) {
        return;
    }
    server = (jayess_libuv_tcp_server *)server_stream->data;
    if (server == NULL || server->listen_callback == NULL) {
        return;
    }
    result = jayess_object_new();
    if (status < 0) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string(uv_strerror(status))));
        jayess_call_function(server->listen_callback, jayess_value_from_object(result));
        return;
    }
    if (server->pending_client != NULL) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string("pending uv tcp client not yet accepted")));
        jayess_call_function(server->listen_callback, jayess_value_from_object(result));
        return;
    }
    client = (jayess_libuv_tcp_client *)calloc(1, sizeof(jayess_libuv_tcp_client));
    if (client == NULL) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string("failed to allocate uv tcp client")));
        jayess_call_function(server->listen_callback, jayess_value_from_object(result));
        return;
    }
    client->handle.data = client;
    if (uv_tcp_init(server->loop, &client->handle) != 0 || uv_accept(server_stream, (uv_stream_t *)&client->handle) != 0) {
        free(client);
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string("failed to accept uv tcp client")));
        jayess_call_function(server->listen_callback, jayess_value_from_object(result));
        return;
    }
    server->pending_client = client;
    jayess_object_set_value(result, "ok", jayess_value_from_bool(1));
    jayess_object_set_value(result, "error", jayess_value_undefined());
    jayess_call_function(server->listen_callback, jayess_value_from_object(result));
}

