static void jayess_libuv_read_file_request_free(jayess_libuv_read_file_request *state) {
    if (state == NULL) {
        return;
    }
    uv_fs_req_cleanup(&state->open_req);
    uv_fs_req_cleanup(&state->stat_req);
    uv_fs_req_cleanup(&state->read_req);
    uv_fs_req_cleanup(&state->close_req);
    free(state->buffer);
    free(state->path);
    free(state->error_message);
    free(state);
}

static void jayess_libuv_finish_read_file(jayess_libuv_read_file_request *state, const char *error_name, const char *error_message) {
    jayess_object *result = jayess_object_new();
    if (error_name != NULL) {
        jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
        jayess_object_set_value(result, "data", jayess_value_undefined());
        jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string(error_name), jayess_value_from_string(error_message != NULL ? error_message : error_name)));
    } else {
        if (state->buffer == NULL) {
            state->buffer = (char *)calloc(1, 1);
            if (state->buffer == NULL) {
                jayess_object_set_value(result, "ok", jayess_value_from_bool(0));
                jayess_object_set_value(result, "data", jayess_value_undefined());
                jayess_object_set_value(result, "error", jayess_std_error_new(jayess_value_from_string("LibUVError"), jayess_value_from_string("failed to allocate libuv read buffer")));
                jayess_call_function(state->callback, jayess_value_from_object(result));
                jayess_libuv_read_file_request_free(state);
                return;
            }
        }
        state->buffer[state->length] = '\0';
        jayess_object_set_value(result, "ok", jayess_value_from_bool(1));
        jayess_object_set_value(result, "data", jayess_value_from_string(state->buffer));
        jayess_object_set_value(result, "error", jayess_value_undefined());
    }
    jayess_call_function(state->callback, jayess_value_from_object(result));
    jayess_libuv_read_file_request_free(state);
}

static void jayess_libuv_read_file_close_cb(uv_fs_t *req) {
    jayess_libuv_read_file_request *state = (jayess_libuv_read_file_request *)req->data;
    if (state == NULL) {
        return;
    }
    if (req->result < 0) {
        jayess_libuv_finish_read_file(state, "LibUVError", uv_strerror((int)req->result));
        return;
    }
    if (state->error_message != NULL) {
        jayess_libuv_finish_read_file(state, "LibUVError", state->error_message);
    } else {
        jayess_libuv_finish_read_file(state, NULL, NULL);
    }
}

static void jayess_libuv_read_file_after_read(uv_fs_t *req) {
    jayess_libuv_read_file_request *state = (jayess_libuv_read_file_request *)req->data;
    uv_buf_t buf;
    if (state == NULL) {
        return;
    }
    if (req->result < 0) {
        state->close_req.data = state;
        state->error_message = strdup(uv_strerror((int)req->result));
        if (uv_fs_close(state->loop, &state->close_req, state->file, jayess_libuv_read_file_close_cb) < 0) {
            jayess_libuv_finish_read_file(state, "LibUVError", state->error_message != NULL ? state->error_message : "failed to close libuv file");
        }
        return;
    }
    if (req->result == 0) {
        state->close_req.data = state;
        if (uv_fs_close(state->loop, &state->close_req, state->file, jayess_libuv_read_file_close_cb) < 0) {
            jayess_libuv_finish_read_file(state, "LibUVError", "failed to close libuv file");
        }
        return;
    }
    state->length += (size_t)req->result;
    if (state->length >= state->capacity) {
        state->close_req.data = state;
        if (uv_fs_close(state->loop, &state->close_req, state->file, jayess_libuv_read_file_close_cb) < 0) {
            jayess_libuv_finish_read_file(state, "LibUVError", "failed to close libuv file");
        }
        return;
    }
    buf = uv_buf_init(state->buffer + state->length, (unsigned int)(state->capacity - state->length));
    state->read_req.data = state;
    if (uv_fs_read(state->loop, &state->read_req, state->file, &buf, 1, -1, jayess_libuv_read_file_after_read) < 0) {
        jayess_libuv_finish_read_file(state, "LibUVError", "failed to continue libuv read");
    }
}

static void jayess_libuv_read_file_after_stat(uv_fs_t *req) {
    jayess_libuv_read_file_request *state = (jayess_libuv_read_file_request *)req->data;
    uv_buf_t buf;
    size_t size = 0;
    if (state == NULL) {
        return;
    }
    if (req->result < 0) {
        state->close_req.data = state;
        state->error_message = strdup(uv_strerror((int)req->result));
        if (uv_fs_close(state->loop, &state->close_req, state->file, jayess_libuv_read_file_close_cb) < 0) {
            jayess_libuv_finish_read_file(state, "LibUVError", state->error_message != NULL ? state->error_message : "failed to close libuv file");
        }
        return;
    }
    size = (size_t)req->statbuf.st_size;
    state->capacity = (size > 0 ? size : 1) + 1;
    state->buffer = (char *)calloc(state->capacity > 0 ? state->capacity : 1, 1);
    if (state->buffer == NULL) {
        state->close_req.data = state;
        state->error_message = strdup("failed to allocate libuv read buffer");
        if (uv_fs_close(state->loop, &state->close_req, state->file, jayess_libuv_read_file_close_cb) < 0) {
            jayess_libuv_finish_read_file(state, "LibUVError", state->error_message != NULL ? state->error_message : "failed to close libuv file");
        }
        return;
    }
    buf = uv_buf_init(state->buffer, (unsigned int)(size > 0 ? size : 1));
    state->read_req.data = state;
    if (uv_fs_read(state->loop, &state->read_req, state->file, &buf, 1, -1, jayess_libuv_read_file_after_read) < 0) {
        jayess_libuv_finish_read_file(state, "LibUVError", "failed to start libuv read");
    }
}

static void jayess_libuv_read_file_after_open(uv_fs_t *req) {
    jayess_libuv_read_file_request *state = (jayess_libuv_read_file_request *)req->data;
    if (state == NULL) {
        return;
    }
    if (req->result < 0) {
        jayess_libuv_finish_read_file(state, "LibUVError", uv_strerror((int)req->result));
        return;
    }
    state->file = (uv_file)req->result;
    state->stat_req.data = state;
    if (uv_fs_fstat(state->loop, &state->stat_req, state->file, jayess_libuv_read_file_after_stat) < 0) {
        jayess_libuv_finish_read_file(state, "LibUVError", "failed to start libuv fstat");
    }
}

static int jayess_libuv_throw_if_error(int code, const char *context) {
    if (code >= 0) {
        return 0;
    }
    jayess_throw_named_error("LibUVError", uv_strerror(code));
    (void)context;
    return 1;
}

