jayess_value *jayess_libuv_read_file_native(jayess_value *loop_value, jayess_value *path_value, jayess_value *callback_value) {
    jayess_libuv_loop_handle *handle = (jayess_libuv_loop_handle *)jayess_expect_native_handle(loop_value, "UVLoop", "jayess_libuv_read_file_native");
    jayess_libuv_read_file_request *state = NULL;
    const char *path = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    path = jayess_expect_string(path_value, "jayess_libuv_read_file_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (callback_value == NULL) {
        jayess_throw_not_function();
        return jayess_value_undefined();
    }
    state = (jayess_libuv_read_file_request *)calloc(1, sizeof(jayess_libuv_read_file_request));
    if (state == NULL) {
        jayess_throw_named_error("LibUVError", "failed to allocate libuv read request");
        return jayess_value_undefined();
    }
    state->loop = &handle->loop;
    state->callback = callback_value;
    state->path = strdup(path);
    state->file = (uv_file)-1;
    if (state->path == NULL) {
        jayess_libuv_read_file_request_free(state);
        jayess_throw_named_error("LibUVError", "failed to copy libuv path");
        return jayess_value_undefined();
    }
    state->open_req.data = state;
    if (uv_fs_open(state->loop, &state->open_req, state->path, O_RDONLY, 0, jayess_libuv_read_file_after_open) < 0) {
        jayess_libuv_read_file_request_free(state);
        jayess_throw_named_error("LibUVError", "failed to start libuv file open");
        return jayess_value_undefined();
    }
    return jayess_value_undefined();
}

