jayess_value *jayess_libuv_spawn_process_native(jayess_value *loop_value, jayess_value *file_value, jayess_value *args_value, jayess_value *callback_value) {
    jayess_libuv_loop_handle *handle = (jayess_libuv_loop_handle *)jayess_expect_native_handle(loop_value, "UVLoop", "jayess_libuv_spawn_process_native");
    jayess_libuv_process_handle *state = NULL;
    uv_process_options_t options;
    const char *file = NULL;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    file = jayess_expect_string(file_value, "jayess_libuv_spawn_process_native");
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    if (callback_value == NULL || jayess_value_function_ptr(callback_value) == NULL) {
        jayess_throw_not_function();
        return jayess_value_undefined();
    }
    state = (jayess_libuv_process_handle *)calloc(1, sizeof(jayess_libuv_process_handle));
    if (state == NULL) {
        jayess_throw_named_error("LibUVError", "failed to allocate uv process state");
        return jayess_value_undefined();
    }
    state->callback = callback_value;
    state->file = strdup(file);
    if (state->file == NULL) {
        free(state);
        jayess_throw_named_error("LibUVError", "failed to copy uv process file");
        return jayess_value_undefined();
    }
    if (!jayess_libuv_fill_process_argv(state, file, args_value)) {
        jayess_libuv_process_close_free((uv_handle_t *)&state->handle);
        return jayess_value_undefined();
    }
    memset(&options, 0, sizeof(options));
    options.exit_cb = jayess_libuv_process_exit_cb;
    options.file = state->file;
    options.args = state->argv;
    state->handle.data = state;
    if (jayess_libuv_throw_if_error(uv_spawn(&handle->loop, &state->handle, &options), "jayess_libuv_spawn_process_native")) {
        jayess_libuv_process_close_free((uv_handle_t *)&state->handle);
        return jayess_value_undefined();
    }
    return jayess_value_from_managed_native_handle("UVProcess", state, jayess_libuv_process_finalize);
}

jayess_value *jayess_libuv_close_process_native(jayess_value *process_value) {
    return jayess_value_from_bool(jayess_value_close_native_handle(process_value));
}

